	buf = AppendFloat16(buf, conf.LBatteryCutEnd, 10)
	buf = AppendFloat16(buf, conf.LBatteryRegenCutStart, 10)
	buf = AppendFloat16(buf, conf.LBatteryRegenCutEnd, 10)
	buf = append(buf, conf.LSlowAbsCurrent)
	buf = append(buf, conf.LTempFetStart)
	buf = append(buf, conf.LTempFetEnd)
	buf = append(buf, conf.LTempMotorStart)
	buf = append(buf, conf.LTempMotorEnd)
	buf = AppendFloat16(buf, conf.LTempAccelDec, 10000)
