	for i := 0; i < 8; i++ {
		buf = append(buf, conf.HallTable[i])
	}
	buf = AppendFloat32Auto(buf, conf.HallSlErpm)
	buf = AppendFloat32Auto(buf, conf.FocCurrentKp)
	buf = AppendFloat32Auto(buf, conf.FocCurrentKi)
	buf = AppendFloat32Auto(buf, conf.FocFZv)
	buf = AppendFloat32Auto(buf, conf.FocDtUs)
	buf = append(buf, conf.FocEncoderInverted)
