	buf = append(buf, conf.FocSpeedSoure)
	buf = append(buf, conf.FocShortLsOnZeroDuty)
	buf = append(buf, conf.SpPidLoopRate)
	buf = AppendFloat32Auto(buf, conf.SPidKp)
	buf = AppendFloat32Auto(buf, conf.SPidKi)
	buf = AppendFloat32Auto(buf, conf.SPidKd)
	buf = AppendFloat16(buf, conf.SPidKdFilter, 10000)
	buf = AppendFloat32Auto(buf, conf.SPidMinErpm)
	buf = append(buf, conf.SPidAllowBraking)
	buf = AppendFloat32Auto(buf, conf.SPidRampErpmsS)
	buf = append(buf, conf.SPidSpeedSource)
	buf = AppendFloat32Auto(buf, conf.PPidKp)
	buf = AppendFloat32Auto(buf, conf.PPidKi)
	buf = AppendFloat32Auto(buf, conf.PPidKd)
	buf = AppendFloat32Auto(buf, conf.PPidKdProc)
	buf = AppendFloat16(buf, conf.PPidKdFilter, 10000)
	buf = AppendFloat32Auto(buf, conf.PPidAngDiv)
	buf = AppendFloat16(buf, conf.PPidGainDecAngle, 10)
	buf = AppendFloat32Auto(buf, conf.PPidOffset)
	buf = AppendFloat16(buf, conf.CcStartupBoostDuty, 10000)
	buf = AppendFloat32Auto(buf, conf.CcMinCurrent)
	buf = AppendFloat32Auto(buf, conf.CcGain)
	buf = AppendFloat16(buf, conf.CcRampStepMax, 10000)
	buf = AppendInt32(buf, conf.MFaultStopTimeMs)
	buf = AppendFloat16(buf, conf.MDutyRampStep, 10000)
	buf = AppendFloat32Auto(buf, conf.MCurrentBackoffGain)
	buf = AppendUint32(buf, conf.MEncoderCounts)
	buf = AppendFloat16(buf, conf.MEncoderSinAmp, 1000)
	buf = AppendFloat16(buf, conf.MEncoderCosAmp, 1000)
