// SerializeAppConf serializes an AppConfiguration to bytes, matching the C
// confgenerator_serialize_appconf function byte-for-byte.
func SerializeAppConf(conf *AppConfiguration) []byte {
	buf := make([]byte, 0, 512)

	buf = AppendUint32(buf, AppConfSignature)

	buf = append(buf, conf.ControllerId)
	buf = AppendUint32(buf, conf.TimeoutMsec)
	buf = AppendFloat32Auto(buf, conf.TimeoutBrakeCurrent)
	buf = AppendUint16(buf, conf.CanStatusRate1)
	buf = AppendUint16(buf, conf.CanStatusRate2)
	buf = append(buf, conf.CanStatusMsgsR1)
	buf = append(buf, conf.CanStatusMsgsR2)
	buf = append(buf, conf.CanBaudRate)
	buf = append(buf, conf.PairingDone)
	buf = append(buf, conf.PermanentUartEnabled)
	buf = append(buf, conf.ShutdownMode)
	buf = append(buf, conf.CanMode)
	buf = append(buf, conf.UavcanEscIndex)
	buf = append(buf, conf.UavcanRawMode)
	buf = AppendFloat32Auto(buf, conf.UavcanRawRpmMax)
	buf = append(buf, conf.UavcanStatusCurrentMode)
	buf = append(buf, conf.ServoOutEnable)
	buf = append(buf, conf.KillSwMode)
	buf = append(buf, conf.AppToUse)
	// PPM
	buf = append(buf, conf.AppPpmConf.CtrlType)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.PidMaxErpm)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.Hyst)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.PulseStart)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.PulseEnd)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.PulseCenter)
	buf = append(buf, conf.AppPpmConf.MedianFilter)
	buf = append(buf, conf.AppPpmConf.SafeStart)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.ThrottleExp)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.ThrottleExpBrake)
	buf = append(buf, conf.AppPpmConf.ThrottleExpMode)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.RampTimePos)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.RampTimeNeg)
	buf = append(buf, conf.AppPpmConf.MultiEsc)
	buf = append(buf, conf.AppPpmConf.Tc)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.TcMaxDiff)
	buf = AppendFloat16(buf, conf.AppPpmConf.MaxErpmForDir, 1)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.SmartRevMaxDuty)
	buf = AppendFloat32Auto(buf, conf.AppPpmConf.SmartRevRampTime)
	// ADC
	buf = append(buf, conf.AppAdcConf.CtrlType)
	buf = AppendFloat32Auto(buf, conf.AppAdcConf.Hyst)
	buf = AppendFloat16(buf, conf.AppAdcConf.VoltageStart, 1000)
	buf = AppendFloat16(buf, conf.AppAdcConf.VoltageEnd, 1000)
	buf = AppendFloat16(buf, conf.AppAdcConf.VoltageMin, 1000)
	buf = AppendFloat16(buf, conf.AppAdcConf.VoltageMax, 1000)
	buf = AppendFloat16(buf, conf.AppAdcConf.VoltageCenter, 1000)
	buf = AppendFloat16(buf, conf.AppAdcConf.Voltage2Start, 1000)
	buf = AppendFloat16(buf, conf.AppAdcConf.Voltage2End, 1000)
	buf = append(buf, conf.AppAdcConf.UseFilter)
	buf = append(buf, conf.AppAdcConf.SafeStart)
	buf = append(buf, conf.AppAdcConf.Buttons)
	buf = append(buf, conf.AppAdcConf.VoltageInverted)
	buf = append(buf, conf.AppAdcConf.Voltage2Inverted)
	buf = AppendFloat32Auto(buf, conf.AppAdcConf.ThrottleExp)
	buf = AppendFloat32Auto(buf, conf.AppAdcConf.ThrottleExpBrake)
	buf = append(buf, conf.AppAdcConf.ThrottleExpMode)
	buf = AppendFloat32Auto(buf, conf.AppAdcConf.RampTimePos)
	buf = AppendFloat32Auto(buf, conf.AppAdcConf.RampTimeNeg)
	buf = append(buf, conf.AppAdcConf.MultiEsc)
	buf = append(buf, conf.AppAdcConf.Tc)
	buf = AppendFloat32Auto(buf, conf.AppAdcConf.TcMaxDiff)
	buf = AppendUint16(buf, conf.AppAdcConf.UpdateRateHz)
	// UART
	buf = AppendUint32(buf, conf.AppUartBaudrate)
	// Chuk
	buf = append(buf, conf.AppChukConf.CtrlType)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.Hyst)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.RampTimePos)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.RampTimeNeg)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.StickErpmPerSInCc)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.ThrottleExp)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.ThrottleExpBrake)
	buf = append(buf, conf.AppChukConf.ThrottleExpMode)
	buf = append(buf, conf.AppChukConf.MultiEsc)
	buf = append(buf, conf.AppChukConf.Tc)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.TcMaxDiff)
	buf = append(buf, conf.AppChukConf.UseSmartRev)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.SmartRevMaxDuty)
	buf = AppendFloat32Auto(buf, conf.AppChukConf.SmartRevRampTime)
	// NRF
	buf = append(buf, conf.AppNrfConf.Speed)
	buf = append(buf, conf.AppNrfConf.Power)
	buf = append(buf, conf.AppNrfConf.CrcType)
	buf = append(buf, conf.AppNrfConf.RetryDelay)
	buf = append(buf, conf.AppNrfConf.Retries)
	buf = append(buf, conf.AppNrfConf.Channel)
	buf = append(buf, conf.AppNrfConf.Address[0])
	buf = append(buf, conf.AppNrfConf.Address[1])
	buf = append(buf, conf.AppNrfConf.Address[2])
	buf = append(buf, conf.AppNrfConf.SendCrcAck)
	// PAS
	buf = append(buf, conf.AppPasConf.CtrlType)
	buf = append(buf, conf.AppPasConf.SensorType)
	buf = AppendFloat16(buf, conf.AppPasConf.CurrentScaling, 1000)
	buf = AppendFloat16(buf, conf.AppPasConf.PedalRpmStart, 10)
	buf = AppendFloat16(buf, conf.AppPasConf.PedalRpmEnd, 10)
	buf = append(buf, conf.AppPasConf.InvertPedalDirection)
	buf = AppendUint16(buf, conf.AppPasConf.Magnets)
	buf = append(buf, conf.AppPasConf.UseFilter)
	buf = AppendFloat16(buf, conf.AppPasConf.RampTimePos, 100)
	buf = AppendFloat16(buf, conf.AppPasConf.RampTimeNeg, 100)
	buf = AppendUint16(buf, conf.AppPasConf.UpdateRateHz)
	// IMU
	buf = append(buf, conf.ImuConf.Type)
	buf = append(buf, conf.ImuConf.Mode)
	buf = append(buf, conf.ImuConf.Filter)
	buf = AppendFloat16(buf, conf.ImuConf.AccelLowpassFilterX, 1)
	buf = AppendFloat16(buf, conf.ImuConf.AccelLowpassFilterY, 1)
	buf = AppendFloat16(buf, conf.ImuConf.AccelLowpassFilterZ, 1)
	buf = AppendFloat16(buf, conf.ImuConf.GyroLowpassFilter, 1)
	buf = AppendUint16(buf, conf.ImuConf.SampleRateHz)
	buf = append(buf, conf.ImuConf.UseMagnetometer)
	buf = AppendFloat32Auto(buf, conf.ImuConf.AccelConfidenceDecay)
	buf = AppendFloat32Auto(buf, conf.ImuConf.MahonyKp)
	buf = AppendFloat32Auto(buf, conf.ImuConf.MahonyKi)
	buf = AppendFloat32Auto(buf, conf.ImuConf.MadgwickBeta)
	buf = AppendFloat32Auto(buf, conf.ImuConf.RotRoll)
	buf = AppendFloat32Auto(buf, conf.ImuConf.RotPitch)
	buf = AppendFloat32Auto(buf, conf.ImuConf.RotYaw)
	buf = AppendFloat32Auto(buf, conf.ImuConf.AccelOffsets[0])
	buf = AppendFloat32Auto(buf, conf.ImuConf.AccelOffsets[1])
	buf = AppendFloat32Auto(buf, conf.ImuConf.AccelOffsets[2])
	buf = AppendFloat32Auto(buf, conf.ImuConf.GyroOffsets[0])
	buf = AppendFloat32Auto(buf, conf.ImuConf.GyroOffsets[1])
	buf = AppendFloat32Auto(buf, conf.ImuConf.GyroOffsets[2])

	return buf
}

